CREATE MATERIALIZED VIEW mv_department_sales_rank AS
SELECT employee_id, department_id, salary,
       RANK() OVER (PARTITION BY department_id ORDER BY salary DESC) AS salary_rank
FROM employees;

-- Then query directly from the materialized view:
SELECT * FROM mv_department_sales_rank WHERE department_id = 10;
